  );

  onToolCall?.({ tool: "run_subcalls", args: { calls } });

  const subcallNodes = await runConcurrent(
    calls.map((call, index) => async () => {
      const startMs = Date.now();   // <── per-task startMs, shadows outer startMs
      try {
        const node = await runSubcall({ … });
        return { ...node, parallel: true };
      } catch (err) {
        // …
        return makeSubcallNode({ …, startMs, parallel: true });
      }
    }),
    concurrency,
  );

  for (const node of subcallNodes) {
    trace.recordSubcall(node);     // <── sequential, after all tasks complete
  }

  // …
  trace.recordToolCall({ … });
  return result;
},
```

